<?php session_start(); require 'config/db.php'; require 'includes/functions.php'; require_login(); $title='Kategoritë'; $subtitle='';
if(isset($_GET['delete'])){ $pdo->prepare('DELETE FROM Kategorite WHERE kategoria_id=?')->execute([$_GET['delete']]); redirect('categories.php'); }
if($_SERVER['REQUEST_METHOD']==='POST'){ if(!empty($_POST['kategoria_id'])) $pdo->prepare('UPDATE Kategorite SET emri=?, pershkrimi=? WHERE kategoria_id=?')->execute([$_POST['emri'],$_POST['pershkrimi'],$_POST['kategoria_id']]); else $pdo->prepare('INSERT INTO Kategorite(emri,pershkrimi) VALUES(?,?)')->execute([$_POST['emri'],$_POST['pershkrimi']]); redirect('categories.php'); }
$edit=null; if(isset($_GET['edit'])){ $st=$pdo->prepare('SELECT * FROM Kategorite WHERE kategoria_id=?'); $st->execute([$_GET['edit']]); $edit=$st->fetch(); }
$rows=$pdo->query('SELECT k.*, COUNT(p.produkt_id) produkte FROM Kategorite k LEFT JOIN Produktet p ON p.kategoria_id=k.kategoria_id GROUP BY k.kategoria_id ORDER BY k.emri')->fetchAll(); include 'includes/header.php'; ?>
<div class="section"><div class="card"><h2>Lista e kategorive</h2><div class="table-wrap"><table><tr><th>Emri</th><th>Përshkrimi</th><th>Produkte</th><th>Veprime</th></tr><?php foreach($rows as $r): ?><tr><td><b><?=e($r['emri'])?></b></td><td><?=e($r['pershkrimi'])?></td><td><span class="badge ok"><?=e($r['produkte'])?></span></td><td class="actions"><a class="btn gray" href="categories.php?edit=<?=$r['kategoria_id']?>">Edit</a><a class="btn danger" data-confirm="Ta fshij kategorinë?" href="categories.php?delete=<?=$r['kategoria_id']?>">Fshi</a></td></tr><?php endforeach; ?></table></div></div><div class="card"><h2><?=$edit?'Ndrysho kategori':'Shto kategori'?></h2><form method="post"><input type="hidden" name="kategoria_id" value="<?=e($edit['kategoria_id']??'')?>"><label>Emri</label><input class="input" name="emri" required value="<?=e($edit['emri']??'')?>"><br><br><label>Përshkrimi</label><textarea class="input" name="pershkrimi"><?=e($edit['pershkrimi']??'')?></textarea><br><br><button class="btn primary">Ruaj</button></form></div></div><?php include 'includes/footer.php'; ?>
